import { Injectable } from '@angular/core';
import { AuthService } from './auth.service';
import { BehaviorSubject, interval, Subscription } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class TokenWarningService {
  private warningSubject = new BehaviorSubject<string | null>(null);
  public warning$ = this.warningSubject.asObservable();

  private checkSubscription: Subscription | null = null;
  private readonly CHECK_INTERVAL = 60000; // 每分钟检查一次
  private readonly WARNING_MINUTES = 10; // 提前10分钟警告

  constructor(private authService: AuthService) {}

  // 开始监控token状态
  startMonitoring() {
    this.stopMonitoring(); // 确保没有重复的监控

    if (!this.authService.isLoggedIn()) {
      return;
    }

    this.checkSubscription = interval(this.CHECK_INTERVAL).subscribe(() => {
      this.checkTokenStatus();
    });
  }

  // 停止监控
  stopMonitoring() {
    if (this.checkSubscription) {
      this.checkSubscription.unsubscribe();
      this.checkSubscription = null;
    }
    this.warningSubject.next(null);
  }

  // 手动检查token状态
  checkTokenStatus() {
    if (!this.authService.isLoggedIn()) {
      this.stopMonitoring();
      return;
    }

    const remainingMinutes = this.authService.getTokenRemainingTime();

    if (remainingMinutes <= 0) {
      // Token已过期
      this.warningSubject.next('登录已过期，请重新登录');
      this.stopMonitoring();
    } else if (remainingMinutes <= this.WARNING_MINUTES) {
      // Token即将过期
      this.warningSubject.next(`登录将在 ${remainingMinutes} 分钟后过期，请及时保存工作并重新登录`);
    } else {
      // Token状态正常
      this.warningSubject.next(null);
    }
  }

  // 清除警告
  clearWarning() {
    this.warningSubject.next(null);
  }
}
